ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?hourly_rate WHERE {
  ?p a :Position .
  ?s a :SalaryDetails .
  ?s p:hasPosition ?p .
  ?s p:Hourly_Rate ?hourly_rate .
  ?p p:Title ?title_f .
  FILTER(STR(?title_f) = "Software Developer")
} }
  component_2: { SELECT ?salary_range WHERE {
  ?p a :Position .
  ?s a :SalaryDetails .
  ?s p:hasPosition ?p .
  ?s p:Salary_Range ?salary_range .
  ?p p:Title ?title_f .
  FILTER(STR(?title_f) = "Software Developer")
} }
  full: { SELECT ?salary_range ?hourly_rate WHERE {
  ?p a :Position .
  ?s a :SalaryDetails .
  ?s p:hasPosition ?p .
  ?s p:Salary_Range ?salary_range .
  ?s p:Hourly_Rate ?hourly_rate .
  ?p p:Title ?title_f .
  FILTER(STR(?title_f) = "Software Developer")
} }
}

